// ❌ BAD - hardcoding the checkout bundle into the host build
import { CartComponent } from '../checkout/cart.component';
// This couples the host build to checkout - teams cannot deploy independently.

// ✅ GOOD - Module Federation: host loads checkout at runtime
// webpack.config.js (remote: checkout team)
new ModuleFederationPlugin({
  name: 'checkout',
  filename: 'remoteEntry.js',
  exposes: { './Cart': './src/app/cart/cart.component.ts' },
  shared: { '@angular/core': { singleton: true, strictVersion: true } }
});
// webpack.config.js (host: shell app)
new ModuleFederationPlugin({
  remotes: { checkout: 'checkout@https://checkout.acme.com/remoteEntry.js' },
  shared: { '@angular/core': { singleton: true, strictVersion: true } }
});

// ❌ BAD - manually touching the real DOM in React, bypassing the virtual DOM
function ProductPrice({ price }: { price: number }) {
  document.getElementById('price')!.textContent = `$${price}`;
  return <span id="price" />;
}
// This fights React's reconciler and causes display inconsistencies.

// ✅ GOOD - let React's virtual DOM reconcile the update declaratively
function ProductPrice({ price }: { price: number }) {
  return <span>${price.toFixed(2)}</span>;
  // React diffs this on state change and updates only the text node.
}

// ❌ BAD - expensive sort on every render, even when orders array did not change
function OrderHistory({ orders }: { orders: Order[] }) {
  const sorted = orders.sort((a, b) => b.date.getTime() - a.date.getTime());
  return <ul>{sorted.map(o => <li key={o.id}>{o.reference}</li>)}</ul>;
}

// ✅ GOOD - sort only when orders array reference changes
function OrderHistory({ orders }: { orders: Order[] }) {
  const sorted = useMemo(
    () => [...orders].sort((a, b) => b.date.getTime() - a.date.getTime()),
    [orders]
  );
  const listRef = useRef<HTMLUListElement>(null);
  return <ul ref={listRef}>{sorted.map(o => <li key={o.id}>{o.reference}</li>)}</ul>;
}

// ❌ BAD - drilling the authenticated user through layers that do not need it
function AppShell({ user }: { user: User }) {
  return <Sidebar user={user} />; // Sidebar does not use user itself
}
function Sidebar({ user }: { user: User }) {
  return <UserAvatar user={user} />; // only UserAvatar needs it
}

// ✅ GOOD - Context: provide once at the top, consume directly
const AuthContext = createContext<User | null>(null);
function AppShell({ user }: { user: User }) {
  return (
    <AuthContext.Provider value={user}>
      <Sidebar />
    </AuthContext.Provider>
  );
}
function UserAvatar() {
  const user = useContext(AuthContext); // reads directly, no prop needed
  return <img src={user?.avatarUrl} alt={user?.name} />;
}
